const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNumber = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);

// Date range: last 7 days in ISO 8601
const startDate = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();
const endDate = now.toISOString();

// GitHub is excluded from all Exa queries — GitHub data comes via the dedicated "Fetch GitHub Trending" node
const NO_GITHUB = ['github.com'];

const queries = [
  // ─── RELEASE QUERIES (feed ACT themes) ───────────────────────────
  // These use release/launch/announcement language to find specific events
  { query: 'AI model release announcement new version launch', category: 'vendor', weight: 90, searchCategory: 'news', include_domains: ['openai.com', 'anthropic.com', 'deepmind.google', 'ai.meta.com', 'azure.microsoft.com', 'aws.amazon.com', 'nvidia.com', 'mistral.ai', 'cohere.com', 'groq.com', 'together.ai', 'fireworks.ai', 'huggingface.co', 'cerebras.net', 'blog.google', 'ai.google.dev'] },
  { query: 'AI platform update API changelog pricing enterprise feature release', category: 'vendor_platform', weight: 88, searchCategory: 'news', include_domains: ['openai.com', 'anthropic.com', 'azure.microsoft.com', 'aws.amazon.com', 'nvidia.com', 'mistral.ai', 'cohere.com', 'groq.com', 'together.ai', 'fireworks.ai', 'huggingface.co', 'databricks.com', 'langchain.com', 'llamaindex.ai', 'wandb.ai', 'pinecone.io', 'weaviate.io', 'qdrant.tech', 'arize.com', 'scale.com', 'snowflake.com', 'ibm.com', 'cerebras.net'] },
  { query: 'open source AI model released weights available download',            category: 'opensource',      weight: 68, searchCategory: 'news', exclude_domains: NO_GITHUB },

  // ─── TREND QUERIES (feed WATCH themes) ───────────────────────────
  // These use pattern/shift/adoption language to find ecosystem trends
  { query: 'AI agents enterprise adoption production challenges scaling patterns',  category: 'agents_trend',    weight: 76, searchCategory: 'news', exclude_domains: NO_GITHUB },
  { query: 'enterprise AI infrastructure strategy cost optimization efficiency',    category: 'enterprise_trend', weight: 74, searchCategory: 'news', exclude_domains: NO_GITHUB },
  { query: 'AI compute cost trends GPU availability inference pricing comparison',  category: 'infra_trend',     weight: 68, searchCategory: 'news', exclude_domains: NO_GITHUB },
  { query: 'RAG retrieval augmented generation production evaluation comparison',   category: 'engineering_trend', weight: 65, searchCategory: 'news', exclude_domains: NO_GITHUB },
  { query: 'open source vs proprietary AI models enterprise evaluation benchmark',  category: 'oss_trend',       weight: 66, searchCategory: 'news', exclude_domains: NO_GITHUB },
  { query: 'AI regulation compliance enterprise impact governance policy',          category: 'safety_trend',    weight: 70, searchCategory: 'news', exclude_domains: NO_GITHUB },
  { query: 'generative AI startup funding acquisition consolidation market shift',  category: 'business_trend',  weight: 62, searchCategory: 'news', exclude_domains: NO_GITHUB },

  // ─── RESEARCH QUERIES ────────────────────────────────────────────
  { query: 'large language model benchmark evaluation research results',            category: 'research',        weight: 72, searchCategory: 'research paper', exclude_domains: NO_GITHUB },
  { query: 'LLM inference efficiency serving latency throughput optimization',      category: 'papers',          weight: 80, searchCategory: 'research paper', include_domains: ['arxiv.org', 'paperswithcode.com', 'semanticscholar.org'] },

  // ─── NEWSLETTER & MEDIA QUERIES ──────────────────────────────────
  { query: 'AI weekly roundup infrastructure enterprise trends analysis',           category: 'newsletter',      weight: 74, searchCategory: 'news', include_domains: ['newsletter.theaiedge.io', 'bensbites.com', 'therundown.ai', 'alphasignal.ai', 'substack.com', 'import-ai.net', 'jack-clark.net', 'lastweekin.ai', 'aitidbits.substack.com', 'simonwillison.net'] },
  { query: 'AI news analysis enterprise infrastructure platform trends',            category: 'newsletter_media', weight: 72, searchCategory: 'news', include_domains: ['techcrunch.com', 'venturebeat.com', 'theverge.com', 'arstechnica.com', 'theregister.com', 'semafor.com', 'bloomberg.com', 'reuters.com', 'wired.com', 'thenewstack.io'] },
];

return [{ json: {
  queries,
  pipeline_date: now.toISOString().split('T')[0],
  start_date: startDate,
  end_date: endDate,
  week_number: weekNumber,
  year: now.getFullYear(),
  pipeline_run_id: `run-${Date.now()}`
} }];

const { queries, pipeline_date, start_date, end_date, week_number, year, pipeline_run_id } = $input.first().json;
const exaKey = $vars.EXA_API_KEY;
if (!exaKey) throw new Error('EXA_API_KEY workflow variable not set');

const results = await Promise.allSettled(
  queries.map(async (q) => {
    const body = {
      query: q.query,
      type: q.weight >= 78 ? 'auto' : 'auto',
      numResults: 20,
      startPublishedDate: start_date,
      endPublishedDate: end_date,
      contents: {
        text: { maxCharacters: 3000 },
        highlights: { maxCharacters: 1000 }
      },
      ...(q.searchCategory ? { category: q.searchCategory } : {}),
      ...(q.include_domains ? { includeDomains: q.include_domains } : {}),
      ...(q.exclude_domains ? { excludeDomains: q.exclude_domains } : {})
    };

    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.exa.ai/search',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': exaKey
      },
      body: JSON.stringify(body)
    });

    // Map Exa response to match downstream pipeline format
    const mapped = (res.results || []).map(r => ({
      url: r.url,
      title: r.title,
      content: r.text || (r.highlights || []).join(' '),
      published_date: r.publishedDate || null,
      score: r.score || null
    }));

    return { ...q, results: mapped };
  })
);

const fetched = results.filter(r => r.status === 'fulfilled').map(r => r.value);
const failed  = results.filter(r => r.status === 'rejected');
const total   = fetched.reduce((s, f) => s + f.results.length, 0);

// Detailed logging for debugging
failed.forEach((r, i) => console.log(`Exa FAILED query ${i}: ${r.reason?.message || JSON.stringify(r.reason)}`));
fetched.forEach(f => console.log(`Exa OK [${f.category}]: ${f.results.length} results`));
if (fetched.length > 0 && fetched[0].results.length > 0) {
  const sample = fetched[0].results[0];
  console.log('Exa sample result:', JSON.stringify({ url: sample.url, title: sample.title, published_date: sample.published_date }));
}
console.log(`Exa SUMMARY: ${fetched.length}/${queries.length} queries succeeded | ${total} raw results | ${failed.length} failed`);

return [{ json: { fetched, pipeline_date, week_number, year, pipeline_run_id } }];

// Parallel fetch branches: combine fetched arrays from Exa and GitHub Trending
const allItems = $input.all();
const { pipeline_date, week_number, year, pipeline_run_id } = allItems[0].json;
const fetched = allItems.flatMap(item => item.json.fetched || []);

const seenUrls   = new Set();
const seenTitles = new Set();
const signals    = [];

for (const source of fetched) {
  const { category, weight = 50, results = [] } = source;
  for (const r of results) {
    if (!r.title || !r.url) continue;
    // Skip github.com URLs from Exa — GitHub Trending node handles these exclusively
    if (category !== 'github' && r.url.includes('github.com')) continue;
    // Skip non-AI-infrastructure domains that leak through Exa queries
    const NON_AI_DOMAINS = ['substack.com', 'medium.com/@', 'regensports', 'threads.com'];
    const NON_AI_TITLES = / (video generation|video editing|image editing|photo editing|game bot|personal assistant|recipe|fitness|sports betting|fantasy sports) /i;
    if (NON_AI_TITLES.test(r.title || '')) continue;
    const normTitle = r.title.toLowerCase().replace(/[^a-z0-9]/g, '').substring(0, 60);
    if (seenUrls.has(r.url) || seenTitles.has(normTitle)) continue;
    seenUrls.add(r.url);
    seenTitles.add(normTitle);
    const relevance_score = Math.min(98, Math.round((r.score || 0.5) * weight));
    let hostname = category;
    try { hostname = new URL(r.url).hostname.replace('www.', ''); } catch (_) {}
    signals.push({
      signal_id:    `tv-${Buffer.from(r.url).toString('base64').replace(/[^a-zA-Z0-9]/g, '').substring(0, 32)}`,
      source_type:  category,
      source_name:  hostname,
      source_url:   r.url,
      title:        r.title.substring(0, 200),
      description:  (r.content || '').substring(0, 250),
      relevance_score,
      published_at: r.published_date || null,
      ingested_at:  new Date().toISOString()
    });
  }
}

console.log(`Process Signals: ${signals.length} unique from ~${fetched.reduce((s,f) => s + f.results.length, 0)} raw`);
return [{ json: { signals, total_unique: signals.length, pipeline_date, week_number, year, pipeline_run_id } }];

const { signals, total_unique, pipeline_date, week_number, year, pipeline_run_id } = $input.first().json;

const MULT = {
  vendor: 1.4, vendor_platform: 1.35, github: 1.3, papers: 1.25,
  safety: 1.2, safety_trend: 1.2,
  agents: 1.15, agents_trend: 1.15,
  newsletter: 1.1, newsletter_media: 1.1, newsletter_substack: 1.1,
  enterprise: 1.1, enterprise_trend: 1.1,
  research: 1.05,
  infra: 1.0, infra_trend: 1.0,
  engineering: 0.95, engineering_trend: 0.95,
  opensource: 0.9, oss_trend: 0.9,
  business: 0.85, business_trend: 0.85
};

// Score all signals
const scored = signals
  .map(s => ({ ...s, final_score: Math.round((s.relevance_score || 50) * (MULT[s.source_type] || 1.0)) }))
  .sort((a, b) => b.final_score - a.final_score);

// Per-category caps: vendor signals capped lower to prevent crowding out thematic signals
// Ecosystem signals (github, papers, agents, safety) get higher caps to ensure theme diversity
const CAT_CAPS = {
  vendor: 5, vendor_platform: 5,
  papers: 12, github: 12,
  agents: 10, agents_trend: 10,
  safety: 8, safety_trend: 8,
  newsletter: 8, newsletter_media: 8, newsletter_substack: 8,
  enterprise: 8, enterprise_trend: 8,
  research: 8,
  infra: 8, infra_trend: 8,
  engineering: 6, engineering_trend: 6,
  opensource: 6, oss_trend: 6,
  business: 4, business_trend: 4,
};
const DEFAULT_CAP = 8;

const catCounts = {};
const diverse = [];
const overflow = [];
for (const s of scored) {
  const cat = s.source_type || 'unknown';
  catCounts[cat] = (catCounts[cat] || 0) + 1;
  const cap = CAT_CAPS[cat] ?? DEFAULT_CAP;
  if (catCounts[cat] <= cap) diverse.push(s);
  else overflow.push(s);
}
const top25 = [...diverse, ...overflow].slice(0, 120);

const source_breakdown = top25.reduce((acc, s) => {
  acc[s.source_type] = (acc[s.source_type] || 0) + 1;
  return acc;
}, {});

const signal_cards = top25
  .map(s => { const pubDate = s.published_at ? s.published_at.substring(0, 10) : 'unknown'; return `[${s.signal_id}] [${s.source_type.toUpperCase()}:${s.source_name}] ${s.title} | ${(s.description || '').substring(0, 100).replace(/\n/g, ' ')} (score:${s.final_score}) (pub:${pubDate})`; })
  .join('\n');

console.log(`Rank & Format: ${signals.length} → top 120 | ${JSON.stringify(source_breakdown)}`);
return [{ json: { signal_cards, top_signals: top25, total_ingested: total_unique, top_n: 120, source_breakdown, pipeline_date, week_number, year, pipeline_run_id } }];

const data = $input.first().json;
const { week_number, year } = data;
const prior_week = week_number > 1 ? week_number - 1 : 52;
const prior_year = week_number > 1 ? year : year - 1;
let priorThemes = [];

try {
  const url = $vars.SUPABASE_URL;
  const key = $vars.SUPABASE_KEY;
  if (url && key) {
    const result = await this.helpers.httpRequest({
      method: 'GET',
      url: `${url}/rest/v1/themes?week_number=eq.${prior_week}&year=eq.${prior_year}&select=theme_id,title,signal_type,confidence_score&limit=10&order=confidence_score.desc`,
      headers: { 'apikey': key, 'Authorization': `Bearer ${key}` }
    });
    priorThemes = Array.isArray(result) ? result : [];
    console.log(`Prior context: ${priorThemes.length} themes from week ${prior_week}/${prior_year}`);
  }
} catch (e) {
  console.log('No prior context (first run or Supabase unavailable):', e.message);
}

return [{ json: { ...data, prior_themes: priorThemes, prior_week } }];

const { signal_cards, top_signals, total_ingested, top_n, source_breakdown, prior_themes, prior_week, pipeline_date, week_number, year, pipeline_run_id } = $input.first().json;

const priorContext = prior_themes.length > 0
  ? `PRIOR WEEK (Week ${prior_week}) — reference only for continuations/escalations:\n` +
    prior_themes.map(t => `  - [${t.signal_type}] ${t.title} (confidence: ${t.confidence_score})`).join('\n')
  : 'PRIOR CONTEXT: None (first run)';

return [{ json: {
  week:             `Week ${week_number}/${year} (${pipeline_date})`,
  ingestion_stats:  `${total_ingested} unique signals → top ${top_n} after ranking`,
  source_breakdown: JSON.stringify(source_breakdown),
  prior_context:    priorContext,
  signal_cards,
  top_signals,
  prior_themes,
  week_number, year, pipeline_run_id, total_ingested, top_n, source_breakdown
} }];

