const inputJson = $input.first().json;
console.log('DS input keys:', Object.keys(inputJson).join(', '));

// STEP 0: extract raw text from whatever Verifier Agent emitted
// LangChain agent nodes set json.output = text response.
// Fallback: json.response may be the full LangChain wrapper {generations:[[{text:...}]]}
let rawText = inputJson.output || inputJson.text || null;

if (!rawText && inputJson.response) {
  try {
    const gen = inputJson.response && inputJson.response.generations;
    if (Array.isArray(gen) && gen[0] && gen[0][0] && gen[0][0].text) rawText = gen[0][0].text;
  } catch(e) {}
}
if (!rawText && typeof inputJson.response === 'string') rawText = inputJson.response;

console.log('DS rawText type:', typeof rawText, '| length:', String(rawText || '').length, '| preview:', String(rawText || '').substring(0, 300));

const aiOutput = typeof rawText === 'string' ? rawText : rawText ? JSON.stringify(rawText) : '{}';

let parsed = { themes: [] };

// STRATEGY 1: parse full output directly (happy path — clean JSON)
try {
  const stripped = aiOutput.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
  const candidate = JSON.parse(stripped);
  if (Array.isArray(candidate.themes) && candidate.themes.length) parsed = candidate;
  else if (Array.isArray(candidate) && candidate[0] && candidate[0].theme_id) parsed = { themes: candidate };
} catch(e) {}

// STRATEGY 2: brace-depth sweep from {"themes": position
if (!parsed.themes.length) {
  try {
    const tidx = aiOutput.indexOf('"themes"');
    if (tidx > 0) {
      const open = aiOutput.lastIndexOf('{', tidx);
      if (open !== -1) {
        let d = 0, end = -1;
        for (let i = open; i < aiOutput.length; i++) {
          if (aiOutput[i] === '{') d++;
          else if (aiOutput[i] === '}') { d--; if (d === 0) { end = i; break; } }
        }
        if (end !== -1) {
          const candidate = JSON.parse(aiOutput.substring(open, end + 1));
          if (Array.isArray(candidate.themes) && candidate.themes.length) parsed = candidate;
        }
      }
    }
  } catch(e) {}
}

// STRATEGY 3: scan for every "theme_id" occurrence, extract surrounding complete object
// Handles truncated JSON — recovers all complete themes even if outer wrapper is cut off
if (!parsed.themes.length) {
  try {
    const themeObjects = [];
    let searchFrom = 0;
    while (searchFrom < aiOutput.length) {
      const tidx = aiOutput.indexOf('"theme_id"', searchFrom);
      if (tidx === -1) break;
      const open = aiOutput.lastIndexOf('{', tidx);
      if (open === -1) { searchFrom = tidx + 1; continue; }
      let d = 0, end = -1;
      for (let i = open; i < aiOutput.length; i++) {
        if (aiOutput[i] === '{') d++;
        else if (aiOutput[i] === '}') { d--; if (d === 0) { end = i; break; } }
      }
      if (end !== -1) {
        try {
          const obj = JSON.parse(aiOutput.substring(open, end + 1));
          if (obj.theme_id || obj.title) { themeObjects.push(obj); searchFrom = end + 1; }
          else searchFrom = tidx + 1;
        } catch(e2) { searchFrom = tidx + 1; }
      } else {
        console.log('DS S3: truncated theme at offset', open, '— recovered', themeObjects.length, 'themes before cut');
        break;
      }
    }
    if (themeObjects.length) {
      parsed = { themes: themeObjects };
      console.log('DS S3 recovered', themeObjects.length, 'individual theme objects');
    }
  } catch(e) {}
}

if (!parsed.themes.length) {
  console.error('DS FAIL: all strategies failed. rawText preview:', String(rawText || '').substring(0, 800));
} else {
  console.log('DS SUCCESS: parsed', parsed.themes.length, 'themes');
}

const { week_number, year, pipeline_run_id, total_ingested, top_n, source_breakdown, top_signals } = $('Build Evidence Pack').first().json;

const signalMap = {};
(top_signals || []).forEach(s => { signalMap[s.signal_id] = s; });

const priorThemes = $('Build Evidence Pack').first().json.prior_themes || [];
const meaningful = w => w.length > 3;
const titleWords = title => (title || '').toLowerCase().split(/\W+/).filter(meaningful);
const findPrior = title => {
  const words = new Set(titleWords(title));
  return priorThemes.find(p => titleWords(p.title).filter(w => words.has(w)).length >= 2) || null;
};

const VELOCITY_DELTA = { ACT: 8, WATCH: -5 };
const baseTime = Date.now();

const themes = (parsed.themes || []).map((theme, idx) => {
  let score = theme.confidence_score || 50;
  const sigIds = [...new Set(theme.supporting_signal_ids || [])];
  const types  = new Set(sigIds.map(id => id.split('-')[0]));
  if (types.size >= 3) score += 12;
  else if (types.size >= 2) score += 6;
  if (sigIds.length >= 6) score += 10;
  else if (sigIds.length >= 4) score += 5;
  else if (sigIds.length >= 2) score += 2;
  score += VELOCITY_DELTA[theme.signal_type] || 0;
  if (sigIds.length === 1) score = Math.min(score, 65);
  if (sigIds.length === 0) score = Math.min(score, 40);
  score = Math.max(0, Math.min(95, Math.round(score))); // Cap at 95% — no theme should claim absolute certainty

  const confidence_level = score >= 75 ? 'high' : score >= 50 ? 'medium' : 'low';
  const rawId = theme.theme_id;
  const safeId = (rawId != null && String(rawId).trim()) || `theme-${baseTime}-${idx}`;
  const { supporting_signals, ...rest } = theme;

  const citations = sigIds
    .filter(id => signalMap[id])
    .map(id => ({
      signal_id:    id,
      title:        signalMap[id].title,
      url:          signalMap[id].source_url,
      source_name:  signalMap[id].source_name,
      source_type:  signalMap[id].source_type,
      published_at: signalMap[id].published_at
    }));

  const priorMatch = findPrior(theme.title);
  return {
    ...rest,
    theme_id:              safeId,
    confidence_score:      score,
    confidence_level,
    supporting_signal_ids: sigIds,
    citations,
    signal_count:          sigIds.length,
    is_continuation:       !!priorMatch,
    prev_confidence:       priorMatch ? priorMatch.confidence_score : null,
    confidence_delta:      priorMatch ? score - priorMatch.confidence_score : null,
    week_number, year,
    processed_at:          new Date().toISOString()
  };
});

themes.sort((a, b) => b.confidence_score - a.confidence_score);
console.log(`Scored ${themes.length} themes | Avg confidence: ${Math.round(themes.reduce((s,t) => s + t.confidence_score, 0) / (themes.length || 1))}`);
return [{ json: { themes, week_number, year, pipeline_run_id, total_ingested, source_breakdown } }];

