const briefText = $input.first().json.output || '';
const { themes, week_number, year, pipeline_run_id, total_ingested } = $('Deterministic Score + Confidence').first().json;
const prompt_version_id = $('Save Prompt Version').first().json.prompt_version_id || null;

const url = $vars.SUPABASE_URL;
const key = $vars.SUPABASE_KEY;
if (!url || !key) throw new Error('SUPABASE_URL or SUPABASE_KEY workflow variable not set');

const headers = {
  'apikey': key,
  'Authorization': `Bearer ${key}`,
  'Content-Type': 'application/json',
  'Prefer': 'resolution=merge-duplicates'
};

const asText = v => Array.isArray(v) ? v.join('\n') : (v || null);

// ── GOLDEN SET ROUTING ──────────────────────────────────────────────────────
// If run_id starts with "run-golden-set-", save to golden_set_* tables instead
// of production tables. This keeps eval data isolated from live briefs.
const isGoldenSet = pipeline_run_id && pipeline_run_id.startsWith('run-golden-set-');

if (isGoldenSet) {
  console.log(`=== GOLDEN SET RUN — saving to golden_set_runs + golden_set_themes ===`);
  console.log(`Run ID: ${pipeline_run_id} | Themes: ${themes.length}`);

  // Save to golden_set_runs
  const gsRun = {
    id:                    pipeline_run_id,
    golden_set_version:    'gs-v2.1',
    prompt_version:        prompt_version_id,
    run_date:              new Date().toISOString().split('T')[0],
    signals_processed:     20,
    themes_produced:       themes.length,
    trap_signals_excluded: null, // fill in manually after scoring
    rule3_edge_case:       null, // fill in manually: 'WATCH' or 'ACT'
    notes:                 `Automated golden set run. Prompt: ${prompt_version_id || 'unknown'}. Score manually using CalmFalcon Golden Set - 20 Signals.md`
  };

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${url}/rest/v1/golden_set_runs?on_conflict=id`,
      headers,
      body: JSON.stringify([gsRun])
    });
    console.log('golden_set_runs: saved OK');
  } catch(e) {
    throw new Error(`SAVE FAILED [golden_set_runs]: ${e.message}`);
  }

  // Save to golden_set_themes
  const gsThemeRows = themes.map(t => ({
    run_id:             pipeline_run_id,
    golden_set_version: 'gs-v1',
    theme_id:           t.theme_id,
    title:              t.title,
    signal_type:        t.signal_type,
    confidence_score:   t.confidence_score,
    summary:            asText(t.summary),
    why_it_matters:     asText(t.why_it_matters),
