  });
  // Check pairwise overlap: at least 50% of signal pairs must share ≥2 keywords
  let coherentPairs = 0, totalPairs = 0;
  for (let i = 0; i < sigKeywords.length; i++) {
    for (let j = i + 1; j < sigKeywords.length; j++) {
      totalPairs++;
      const overlap = [...sigKeywords[i]].filter(w => sigKeywords[j].has(w)).length;
      if (overlap >= 2) coherentPairs++;
    }
  }
  const coherenceRatio = totalPairs > 0 ? coherentPairs / totalPairs : 0;
  if (coherenceRatio < 0.2) {
    console.log(`Cluster kw-${kw}: dropped (coherence ${(coherenceRatio*100).toFixed(0)}% < 20%)`);
    continue;
  }

  unique.forEach(s => usedIds.add(s.signal_id));
  const topSig = unique.sort((a,b) => b.score - a.score)[0];
  clusters.push({
    cluster_id: `kw-${kw}`,
    working_title: `${kw.charAt(0).toUpperCase() + kw.slice(1)} — ${topSig.title.substring(0, 50)}`,
    signal_ids: unique.map(s => s.signal_id),
    signal_count: unique.length,
    cluster_type: 'keyword',
    top_signal_title: topSig.title,
    max_score: topSig.score
  });
}

// ── STEP 3: SINGLETON FALLBACK ────────────────────────────────────
// High-scoring non-vendor signals that didn't land in any keyword cluster
const highValueSingletons = nonVendorSignals
  .filter(s => !usedIds.has(s.signal_id) && s.score >= 65)
  .sort((a,b) => b.score - a.score)
  .slice(0, 5);

for (const s of highValueSingletons) {
  clusters.push({
    cluster_id: `single-${s.signal_id.substring(0,8)}`,
    working_title: s.title.substring(0, 80),
    signal_ids: [s.signal_id],
    signal_count: 1,
    cluster_type: 'singleton',
    top_signal_title: s.title,
    max_score: s.score
  });
}

// ── STEP 4: MERGE GITHUB RELEASE SINGLETONS ──────────────────
// Single-signal GitHub releases flood theme slots. Merge them into one "roundup" cluster.
// Only major releases (from repos with >5000 stars in content) stay standalone.
// Identify ALL GitHub release clusters (singletons, keyword singles, or any cluster
// where ALL signals are from github.com with release-like titles)
function isGithubRelease(cluster) {
  if (!cluster.top_signal_title) return false;
  const title = cluster.top_signal_title;
  const isRelease = title.includes('github.com') || title.startsWith('RELEASE:') || 
    title.startsWith('NEW:') || /releases? v?\d/i.test(title) || /v\d+\.\d+/i.test(title);
  // For multi-signal clusters, only merge if ALL signals are GitHub releases
  if (cluster.signal_count > 1 && cluster.cluster_type === 'keyword') {
    const allGithub = cluster.signal_ids.every(id => {
      const sig = parsed.find(p => p.signal_id === id);
      return sig && (sig.domainStr.includes('github.com') || /releases? v?\d/i.test(sig.title) || /v\d+\.\d+/i.test(sig.title));
    });
    return allGithub;
  }
  return isRelease && cluster.signal_count <= 2;
}
const allGithubSingles = clusters.filter(c => 
  (c.cluster_type === 'singleton' || c.cluster_type === 'keyword') && isGithubRelease(c)
);

if (allGithubSingles.length >= 2) {
  // Remove individual singletons from clusters
  const singleIds = new Set(allGithubSingles.map(c => c.cluster_id));
  const filtered = clusters.filter(c => !singleIds.has(c.cluster_id));

  // Create merged roundup cluster
  const mergedIds = allGithubSingles.flatMap(c => c.signal_ids);
  const topSig = allGithubSingles.sort((a, b) => b.max_score - a.max_score)[0];
  filtered.push({
    cluster_id: 'roundup-github-releases',
    working_title: `AI Framework Release Roundup — ${allGithubSingles.length} releases this week`,
    signal_ids: mergedIds,
    signal_count: mergedIds.length,
    cluster_type: 'roundup',
    top_signal_title: topSig.top_signal_title,
    max_score: topSig.max_score
  });

  console.log(`Merged ${allGithubSingles.length} GitHub release singletons into 1 roundup cluster`);
  clusters.length = 0;
  clusters.push(...filtered);
}

// Sort: vendor first, then keyword by signal count, then singletons
clusters.sort((a, b) => {
  const typeOrder = { vendor: 0, keyword: 1, singleton: 2 };
  if (typeOrder[a.cluster_type] !== typeOrder[b.cluster_type])
    return typeOrder[a.cluster_type] - typeOrder[b.cluster_type];
  return b.signal_count - a.signal_count;
});

const signal_clusters = JSON.stringify({ clusters }, null, 2);
const signal_card_titles = (top_signals || []).map(s => `[${s.signal_id}] ${s.title}`).join('\n');

console.log(`Signal Cluster Builder: ${parsed.length} signals → ${Object.keys(vendorGroups).length} vendor clusters + ${clusters.filter(c=>c.cluster_type==='keyword').length} keyword clusters + ${clusters.filter(c=>c.cluster_type==='singleton').length} singletons = ${clusters.length} total`);

return [{ json: { ...rest, signal_cards, top_signals, signal_clusters, signal_card_titles } }];

