// SPLIT CLUSTERS — parses Theme Selector output, emits one item per cluster
const raw = $input.first().json.output || '{}';
const evidencePack = $('Build Evidence Pack').first().json;
const signalMap = {};
(evidencePack.top_signals || []).forEach(s => { signalMap[s.signal_id] = s; });

let clusters = [];

// Strategy 1: clean parse
try {
  const m = raw.match(/\{[\s\S]*"selected_clusters"[\s\S]*\}/);
  if (m) clusters = JSON.parse(m[0]).selected_clusters || [];
  else clusters = JSON.parse(raw).selected_clusters || [];
} catch(e) {
  // Strategy 2: truncated JSON — extract complete cluster objects individually
  console.log(`Split Clusters: clean parse failed (${e.message}) — attempting partial recovery`);
  try {
    // Find each complete cluster object {...} between the array brackets
    const arrayMatch = raw.match(/"selected_clusters"\s*:\s*\[([^]*)/);
    if (arrayMatch) {
      const arrayContent = arrayMatch[1];
      // Match complete objects: find balanced { } blocks
      let depth = 0, start = -1;
      for (let i = 0; i < arrayContent.length; i++) {
        if (arrayContent[i] === '{') {
          if (depth === 0) start = i;
          depth++;
        } else if (arrayContent[i] === '}') {
          depth--;
          if (depth === 0 && start !== -1) {
            try {
              const obj = JSON.parse(arrayContent.substring(start, i + 1));
              if (obj.working_title || obj.cluster_id) clusters.push(obj);
            } catch(innerE) {}
            start = -1;
          }
        }
      }
      console.log(`Split Clusters: partial recovery found ${clusters.length} complete cluster objects`);
    }
  } catch(e2) {
    throw new Error(`Split Clusters: all parse strategies failed — raw: ${raw.substring(0, 400)}`);
  }
}

if (clusters.length < 3) {
  throw new Error(`Split Clusters: only ${clusters.length} clusters found — Theme Selector output: ${raw.substring(0, 400)}`);
}

console.log(`Split Clusters: emitting ${clusters.length} clusters for Theme Writer`);

return clusters.map((cluster, idx) => {
  const ids = cluster.signal_ids || [];
  const cards = ids
    .filter(id => signalMap[id])
    .map(id => {
      const s = signalMap[id];
      return `[${s.signal_id}] ${s.title} | ${s.source_url} | pub:${s.published_at || 'unknown'} | cat:${s.source_name}`;
    })
    .join('\n');

  // Fallback: if no cluster_cards matched by ID, search signalMap by keyword from working_title
  let finalCards = cards;
  let finalIds = ids;
  if (!cards) {
    const keywords = (cluster.working_title || '').toLowerCase().split(/\s+/)
      .filter(w => w.length > 3 && !['with','from','and','the','for','into','that','this','using'].includes(w));
    const fallbackSignals = Object.values(signalMap).filter(s => {
      const title = (s.title || '').toLowerCase();
      return keywords.some(kw => title.includes(kw));
    }).slice(0, 5);
    if (fallbackSignals.length > 0) {
      finalIds = fallbackSignals.map(s => s.signal_id);
      finalCards = fallbackSignals.map(s =>
        `[${s.signal_id}] ${s.title} | ${s.source_url} | pub:${s.published_at || 'unknown'} | cat:${s.source_name}`
      ).join('\n');
      console.log(`Split Clusters [${cluster.working_title}]: ID mismatch — keyword fallback found ${fallbackSignals.length} signals`);
    } else {
      finalCards = '(no matching signal cards — IDs may not match signal map and keyword fallback found nothing)';
      console.log(`Split Clusters [${cluster.working_title}]: WARNING — no signal cards found via ID or keyword`);
    }
  }

  return {
    json: {
      cluster_index:   idx + 1,
      cluster_id:      cluster.cluster_id || `c${String(idx+1).padStart(3,'0')}`,
      working_title:   cluster.working_title || `Cluster ${idx+1}`,
      topic_anchor:    cluster.topic_anchor || '',
      signal_ids:      finalIds,
      cluster_cards:   finalCards,
      week_number:     evidencePack.week_number,
      year:            evidencePack.year,
      pipeline_run_id: evidencePack.pipeline_run_id,
      total_ingested:  evidencePack.total_ingested,
    }
  };
});

