// AGGREGATE THEMES — collects all Theme Writer outputs into a single themes array
const items = $input.all();
const evidencePack = $('Build Evidence Pack').first().json;

const themes = [];
const parseErrors = [];

for (let i = 0; i < items.length; i++) {
  const raw = (items[i].json.output || '').trim();
  let parsed = null;

  // Strategy 1: brace-depth counter — find first complete JSON object containing "theme_id"
  // (avoids greedy regex failure when Theme Writer outputs preamble text before JSON)
  try {
    const tidx = raw.indexOf('"theme_id"');
    if (tidx !== -1) {
      const open = raw.lastIndexOf('{', tidx);
      if (open !== -1) {
        let d = 0, end = -1;
        for (let i = open; i < raw.length; i++) {
          if (raw[i] === '{') d++;
          else if (raw[i] === '}') { d--; if (d === 0) { end = i; break; } }
        }
        if (end !== -1) {
          const candidate = JSON.parse(raw.substring(open, end + 1));
          if (candidate.title || candidate.theme_id) parsed = candidate;
        }
      }
    }
  } catch(e) {}

  // Strategy 2: strip markdown fences and parse full output
  if (!parsed) {
    try {
      const stripped = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
      const candidate = JSON.parse(stripped);
      // Accept if it looks like a theme (has title) or has a themes array
      if (candidate.title) parsed = candidate;
      else if (candidate.themes && candidate.themes[0]) parsed = candidate.themes[0];
    } catch(e) {}
  }

  // Strategy 3: find first {...} block regardless of theme_id
  if (!parsed) {
    try {
      const m3 = raw.match(/\{[\s\S]+\}/);
      if (m3) {
        const candidate = JSON.parse(m3[0]);
        if (candidate.title || candidate.theme_id) parsed = candidate;
      }
    } catch(e) {}
  }

  if (parsed && (parsed.title || parsed.theme_id)) {
    parsed.theme_id = `theme-${String(themes.length + 1).padStart(3, '0')}`;
    themes.push(parsed);
  } else {
    const snippet = raw.substring(0, 200);
    parseErrors.push(`item ${i+1}: could not parse — raw: ${snippet}`);
    console.log(`Aggregate PARSE FAIL item ${i+1}: ${snippet}`);
  }
}

console.log(`Aggregate Themes: ${items.length} Theme Writer calls → ${themes.length} valid themes | ${parseErrors.length} parse failures`);

// Fail loudly if nothing was collected — silent 0 makes diagnosis impossible
if (themes.length === 0) {
  const sample = (items[0]?.json?.output || 'no output').substring(0, 400);
  throw new Error(`Aggregate Themes: 0 themes collected from ${items.length} items. First item raw output: ${sample}`);
}

const output = JSON.stringify({ themes });

return [{
  json: {
    output,
    pre_aggregate_count:   items.length,
    collected_theme_count: themes.length,
    parse_failures:        parseErrors.length,
    week_number:      evidencePack.week_number,
    year:             evidencePack.year,
    pipeline_run_id:  evidencePack.pipeline_run_id,
    total_ingested:   evidencePack.total_ingested,
    source_breakdown: evidencePack.source_breakdown,
    signal_cards:     evidencePack.signal_cards,
    top_signals:      evidencePack.top_signals,
    prior_themes:     evidencePack.prior_themes,
  }
}];
